const keywords = [
  'data scientist', 'ml engineer', 'analytics engineer', // más específicos arriba
  'data', 'machine learning', 'ml', 'mlops', 'llmops',
  'ai engineer', 'python', 'analytics', 'scientist',
  'cientifico de datos', 'engineer', 'ingeniero', 'inteligencia'
];

const filtered = $('Guardar empleos').all().filter(item => {
  const title = (item.json.title || '').toLowerCase();
  return keywords.some(k => title.includes(k));
});

// Ordenar por coincidencia con keywords más específicas
filtered.sort((a, b) => {
  const titleA = (a.json.title || '').toLowerCase();
  const titleB = (b.json.title || '').toLowerCase();
  const idxA = keywords.findIndex(k => titleA.includes(k));
  const idxB = keywords.findIndex(k => titleB.includes(k));
  return idxA - idxB;
});

//const result = filtered.slice(0, 5);
const result = filtered; 

// Retornamos un único objeto con los resultados empaquetados
// Esto garantiza que el flujo SIEMPRE continúe al siguiente nodo
return {
  jobs: result.map(item => item.json),
  count: result.length
};

// 1. Obtenemos el array 'data'
const inputData = $input.all()[0].json.data || [];

// 2. Filtramos y transformamos
const matches = inputData
  .filter(item => item.ai_score >= 4)
  .map(item => {
    let highlights = [], redFlags = [];
    try { highlights = typeof item.fit_highlights === 'string' ? JSON.parse(item.fit_highlights) : item.fit_highlights; } catch (e) {}
    try { redFlags = typeof item.red_flags === 'string' ? JSON.parse(item.red_flags) : item.red_flags; } catch (e) {}

    // Limpieza de ubicación (maneja el string "null" y valores nulos reales)
    const rawLocation = String(item.location).toLowerCase();
    const cleanLocation = (rawLocation === 'null' || !item.location) ? '' : ` • ${item.location}`;

    return {
      ...item,
      displayLocation: cleanLocation,
      fit_highlights: highlights || [],
      red_flags: redFlags || []
    };
  });

if (matches.length === 0) return [{ json: { status: 'NO_MATCHES' } }];

// 3. Generamos el HTML optimizado
function buildHtml(matches) {
  // Fecha y Hora con formato local
  const ahora = new Date().toLocaleString('es-AR', {
    day: '2-digit', month: 'long', year: 'numeric',
    hour: '2-digit', minute: '2-digit'
  });

  const rows = matches.map(m => {
    const color = m.ai_score === 5 ? '#16a34a' : '#2563eb';
    const emoji = m.ai_score === 5 ? '🔥' : '✅';
    const highlightsHtml = m.fit_highlights.map(h => `<li style='margin-bottom:4px;'>${h}</li>`).join('');
    const flagsHtml = m.red_flags.map(h => `<li style='margin-bottom:4px;'>${h}</li>`).join('');

    return `
      <div style='margin-bottom:24px; padding:24px; border-radius:16px; background:#ffffff; border:1px solid #e2e8f0; box-shadow: 0 4px 6px -1px rgba(0,0,0,0.1);'>
        <!-- Cabecera: Título y Score -->
        <table width="100%" cellpadding="0" cellspacing="0" border="0">
          <tr>
            <td style="vertical-align: top;">
              <h2 style='margin:0; font-size:20px; color:#1e3a8a; line-height:1.2;'>${emoji} ${m.title}</h2>
            </td>
            <td style="vertical-align: top; text-align: right; padding-left: 15px;">
              <span style='background:${color}; color:#ffffff; padding:5px 14px; border-radius:100px; font-size:12px; font-weight:bold; white-space:nowrap; display:inline-block;'>
                SCORE: ${m.ai_score}/5
              </span>
            </td>
          </tr>
        </table>

        <!-- Empresa y Ubicación -->
        <p style='font-size:15px; color:#64748b; margin:10px 0 16px'>
          <strong style="color:#475569">${m.company}</strong>${m.displayLocation}
        </p>

        <!-- Resumen -->
        <div style='background:#f8fafc; padding:16px; border-radius:12px; border:1px solid #f1f5f9; margin-bottom:20px;'>
          <p style='color:#334155; font-size:14px; line-height:1.6; margin:0;'>${m.ai_summary}</p>
        </div>

        <!-- Listas -->
        <table width="100%" cellpadding="0" cellspacing="0" border="0" style="font-size:14px; line-height:1.5;">
          <tr>
            <td style="padding-bottom:15px;">
              <strong style='color:#15803d; display:block; margin-bottom:8px;'>✅ Por qué encaja:</strong>
              <ul style='margin:0; padding-left:20px; color:#166534;'>${highlightsHtml}</ul>
            </td>
          </tr>
          ${flagsHtml ? `
          <tr>
            <td>
              <strong style='color:#b91c1c; display:block; margin-bottom:8px;'>⚠️ Atención con:</strong>
              <ul style='margin:0; padding-left:20px; color:#991b1b;'>${flagsHtml}</ul>
            </td>
          </tr>` : ''}
        </table>

        <!-- Botón -->
        <div style='margin-top:24px; text-align:right;'>
          <a href='${m.job_url}' style='background:#1e40af; color:#ffffff; padding:10px 24px; border-radius:8px; text-decoration:none; font-weight:bold; font-size:14px; display:inline-block;'>Aplicar en LinkedIn →</a>
        </div>
      </div>`;
  }).join('');

  return `
    <!DOCTYPE html>
    <html>
      <body style='margin:0; padding:40px 20px; background:#f1f5f9; font-family:-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;'>
        <div style='max-width:600px; margin:0 auto;'>
          <div style='text-align:center; margin-bottom:30px;'>
            <h1 style='color:#0f172a; margin:0; font-size:26px;'>🎯 Nuevos Matches</h1>
            <p style='color:#64748b; margin:10px 0 0; font-size:14px;'>Reporte del <b>${ahora}</b></p>
            <div style="height:2px; width:40px; background:#2563eb; margin:20px auto;"></div>
          </div>
          ${rows}
          <div style='text-align:center; padding:20px; color:#94a3b8; font-size:12px;'>
            <p>Este es un sistema inteligente de búsqueda — ${ahora}</p>
          </div>
        </div>
      </body>
    </html>`;
}

return [{ 
  json: { 
    status: 'MATCHES_FOUND', 
    count: matches.length, 
    html: buildHtml(matches) 
  } 
}];
